  "get_order": {"fn": get_order, "required": ["order_id"]},
}

def dispatch(call):
    spec = REGISTRY.get(call["name"])
    missing = [a for a in spec["required"] if a not in call["args"]]
    if missing:
        return {"error": f"missing required arg: {missing[0]}"}
    return spec["fn"](**call["args"])

